items.code:
table {
  border-collapse: collapse;
  width: 100%;
}

th {
  background: #1e293b;
  color: #fff;
  padding: 0.75rem;
  text-align: left;
}

td {
  padding: 0.75rem;
  border-bottom: 1px solid #e2e8f0;
}

/* ゼブラストライプ */
tbody tr:nth-child(even) {
  background-color: #f8fafc;
}

/* ホバー効果 */
tbody tr:hover {
  background-color: #eef2ff;
}

/* 横スクロール方式（最も簡単） */
.table-responsive {
  overflow-x: auto;
  -webkit-overflow-scrolling: touch;
}

/* カード型変換（小画面用） */
@media (max-width: 640px) {
  table, thead, tbody, th, td, tr {
    display: block;
  }
  thead { display: none; }
  tr {
    margin-bottom: 1rem;
    border: 1px solid #e2e8f0;
    border-radius: 0.5rem;
  }
  td {
    display: flex;
    justify-content: space-between;
    padding: 0.5rem;
    border-bottom: 1px solid #f1f5f9;
  }
  td::before {
    content: attr(data-label);
    font-weight: 600;
  }
}

/* ::marker で色・サイズ変更 */
li::marker {
  color: #3b82f6;
  font-size: 1.2em;
}

/* 絵文字マーカー */
ul.emoji {
  list-style: none;
  padding-left: 0;
}
ul.emoji li::before {
  content: "✅ ";
}

/* CSSカウンター */
ol.custom {
  list-style: none;
  counter-reset: item;
}
ol.custom li::before {
  counter-increment: item;
  content: counter(item) ". ";
  color: #3b82f6;
  font-weight: 700;
}
